type Mode = "" | "upload" | "single" | "batch";
type FileStatus = "pending" | "processing" | "success" | "failed";

type StepItem = {
  step?: number;
  time?: string;
  title?: string;
  description?: string;
  confidence?: number;
};

type BatchFileItem = {
  filename: string;
  filepath: string;
  status: FileStatus;
  error: string;
};

type SingleResultData = {
  steps: StepItem[];
  markdown: string;
  output_dir: string;
  pdf_path?: string;
};

type BatchResultItem = {
  index?: number;
  filename: string;
  success: boolean;
  steps_count?: number;
  output_dir?: string;
  error?: string;
};

type BatchResultData = {
  results: BatchResultItem[];
  summary?: {
    total?: number;
    success?: number;
    failed?: number;
  };
};

type HistoryItem = {
  id: string;
  video_name: string;
  mode?: string;
  steps_count?: number;
  timestamp?: string;
};

type ProgressBoard = {
  mode: Mode;
  percent: number;
  stage: string;
  total: number;
  current: number;
  success: number;
  failed: number;
  currentFile: string;
};

const DEFAULT_PROGRESS_BOARD: ProgressBoard = {
  mode: "",
  percent: 0,
  stage: "",
  total: 0,
  current: 0,
  success: 0,
  failed: 0,
  currentFile: "",
};

const isValidVideo = (filename: string) => {
  const ext = String(filename || "").split(".").pop()?.toLowerCase() || "";
  return VALID_VIDEO_EXTENSIONS.has(ext);
};

const basename = (value: string | undefined | null) =>
  String(value || "")
    .split(/[\\/]/)
    .filter(Boolean)
    .pop() || "";

const clone = <T,>(value: T): T => JSON.parse(JSON.stringify(value)) as T;

